#include <bits/stdc++.h>
using namespace std;
int n,a[10004],sum,cnt;
int val[100005],len=1;
int main(){
    scanf("%d",&n);
    val[1]=1;
    for(int i=2;sum<=n;i++){
    	a[i-1]=i,sum+=i,cnt++;
	}
	int del=sum-n;
	if(del==1)
		del=2,a[cnt]++;
    for(int i=1;i<=cnt;i++){
    	if(del==a[i])
    		continue;
        printf("%d ",a[i]);
        for(int j=1;j<=len;j++)
        	val[j]*=a[i];
        for(int j=1;j<=len;j++){
        	val[j+1]+=val[j]/10;
			val[j]%=10; 
		}
		while(val[len+1])
			len++,val[len+1]+=val[len]/10,val[len]%=10;
    }
    printf("\n");
    for(int i=len;i;i--)	
    	printf("%d",val[i]);
    return 0;
}
